return ['domain'=>NULL,'plural-forms'=>'nplurals=4; plural=(n%100==1 ? 0 : n%100==2 ? 1 : n%100==3 || n%100==4 ? 2 : 3);','language'=>'sl_SI','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Posodobite vtičnik TranslatePress - Multilingual na različico %1$s ali višjo za zagotovitev pravilnega delovanja %2$s.','Please install and activate the TranslatePress - Multilingual plugin'=>'Namestite in aktivirajte vtičnik TranslatePress - Multilingual','Install & Activate'=>'Namesti in aktiviraj','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Posodobite TranslatePress - Multilingual na različico %2$s ali novejšo. Trenutno nameščena različica TranslatePress - Multilingual ni več združljiva s trenutno različico %1$s.','All TranslatePress functionalities are disabled until then.'=>'Vse funkcionalnosti TranslatePress so do takrat onemogočene.','Update Now'=>'Posodobi zdaj','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Ta dodatek za TranslatePress je bil prenesen v glavni vtičnik in se ne uporablja več. Lahko ga izbrišete.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> za delovanje zahteva vsaj različico PHP 5.6.20+. To je <a href="%s">minimalna zahteva najnovejše različice WordPressa</a>. Obrnite se na skrbnika strežnika za posodobitev različice PHP.','Advanced'=>'Napredno','Settings saved.'=>'Nastavitve so shranjene.','Are you sure you want to remove this item?'=>'Ali ste prepričani, da želite odstraniti ta element?','Remove'=>'Odstrani','Add'=>'Dodaj','Select...'=>'Izberi...','[%s] Low TranslatePress AI Words'=>'[%s] Zmanjkuje besed TranslatePress AI','upgrade your plan or get extra AI Words'=>'Nadgradite svoj paket ali pridobite dodatne AI-besede','upgrade your plan'=>'Nadgradite svoj paket','TranslatePress AI words are running low on your site.'=>'Na vašem spletišču zmanjkuje besed TranslatePress AI.','Current status: %s words remaining'=>'Trenutni status: preostalo %s besed','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Ko zmanjka preostalih besed TranslatePress AI, bo samodejni prevod prek TranslatePress AI začasno zaustavljen.','To continue translating your content, please %1$s over at %2$s'=>'Za nadaljevanje prevajanja vsebine %1$s na %2$s','Manage Notification: %s'=>'Upravljanje obvestil: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Na voljo je nova različica %1$s. %2$sOglejte si podrobnosti različice %3$s%4$s ali %5$sposodobite zdaj%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Na voljo je nova različica %1$s. %2$sOglejte si podrobnosti različice %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Če želite omogočiti posodobitve, %1$svnesite licenčni ključ%2$s. Potrebujete licenčni ključ? %3$sKupite ga zdaj%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Če želite omogočiti posodobitve, pojdite na %1$sstran z licenco%2$s in preverite, ali imate veljavno licenco.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Če želite omogočiti posodobitve, morate obnoviti licenco. Pojdite na stran %1$sTranslatePress Account%2$s in se prijavite za obnovitev.','You do not have permission to install plugin updates'=>'Nimate dovoljenja za namestitev posodobitev vtičnika','Error'=>'Napaka','Your TranslatePress license key is invalid or missing.'=>'Vaš licenčni ključ TranslatePress je neveljaven ali manjka.','Your license key expired on %s.'=>'Vaš licenčni ključ je potekel %s.','Your license key has been disabled.'=>'Vaš licenčni ključ je bil onemogočen.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Vaš licenčni ključ je onemogočen za ta URL. Znova ga omogočite na <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Upravljanje strani.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Neujemanje licenčnega ključa.</strong> Vnesena licenca se ne ujema z nameščeno različico TranslatePress.</p><p>Preverite, ali ste iz svojega računa TranslatePress namestili pravilno različico za vašo licenco.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Če imate nameščen samo brezplačni vtičnik, vendar ste dodali plačano licenco, namestite plačani vtičnik iz svojega računa TranslatePress.','Your license key has reached its activation limit.'=>'Vaš licenčni ključ je dosegel omejitev aktivacij.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Nadgradite načrt za dodajanje več strani. %1$sNadgradite zdaj%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'To spletno mesto je že aktivirano pod brezplačno licenco. Vsako spletno mesto lahko uporablja samo eno brezplačno licenco.','An error occurred, please try again.'=>'Prišlo je do napake, poskusite znova.','You have successfully activated your license'=>'Uspešno ste aktivirali svojo licenco.','Others'=>'Ostali','Restrict by Language'=>'Omeji po jeziku','Exclude from Language'=>'Izključi iz jezika','Restrict element to language'=>'Omeji element na jezik','Show this element only in one language.'=>'Prikaži ta element samo v enem jeziku.','Enable translation'=>'Omogoči prevajanje','Allow translation to the corresponding language only if the content is written in the default language.'=>'Dovoli prevajanje v ustrezen jezik le, če je vsebina napisana v privzetem jeziku.','Select language'=>'Izberite jezik','Choose in which language to show this element.'=>'Izberite jezik, v katerem naj se prikaže ta element.','Exclude element from language'=>'Izključi element iz jezika','Exclude this element from specific languages.'=>'Izključi ta element iz določenih jezikov.','Select languages'=>'Izberite jezike','Choose from which languages to exclude this element.'=>'Izberite jezike, iz katerih želite izključiti ta element.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Ta element bo še vedno viden med prevajanjem spletnega mesta v urejevalniku prevodov.','The content of this element should be written in the default language.'=>'Vsebina tega elementa mora biti napisana v privzetem jeziku.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> je naletel na napake SQL. <a href="%s" title="View TranslatePress SQL Errors">Preverite napake</a>.','Automatic translation has been disabled.'=>'Samodejno prevajanje je bilo onemogočeno.','Dismiss this notice.'=>'Zapri to obvestilo.','Logged errors'=>'Zabeležene napake','These are the most recent 5 errors logged by TranslatePress:'=>'To je zadnjih 5 napak, ki jih je zabeležil TranslatePress:','Yes'=>'Da','Why are these errors occuring'=>'Zakaj se pojavljajo te napake','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Če TranslatePress pri izvajanju poizvedb v vaši zbirki podatkov zazna kaj narobe, lahko onemogoči funkcijo samodejnega prevajanja, da se izogne dodatnim stroškom pri Googlu/DeepL. Samodejno prevajanje je treba ročno vklopiti, potem ko odpravite težave.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Zaznane napake SQL se lahko pojavijo iz različnih razlogov, vključno z manjkajočimi tabelami, manjkajočimi dovoljenji za uporabnika SQL za ustvarjanje tabel ali izvajanje drugih operacij, težavami po selitvi spletišča ali spremembami konfiguracije strežnika SQL.','What you can do in this situation'=>'Kaj lahko storite v tej situaciji','Plan A.'=>'Načrt A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Pojdite v Nastavitve -> TranslatePress -> zavihek Splošno in shranite nastavitve. S tem boste regenerirali tabele z uporabo trenutnih nastavitev SQL. Preverite, ali se pri brskanju po vašem spletišču v prevedenem jeziku ne pojavljajo več napake. Poglejte časovne žige napak, da se prepričate, da ne vidite starih napak. Prikazanih je samo najnovejših 5 napak.','Plan B.'=>'Načrt B.','If your problem isn\'t solved, try the following steps:'=>'Če vaša težava ni odpravljena, poskusite naslednje korake:','Create a backup of your database'=>'Ustvarite varnostno kopijo svoje zbirke podatkov','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Ustvarite kopijo vsake tabele za prevode, kjer naletite na napake. Tabelo lahko kopirate znotraj iste zbirke podatkov (npr. trp_dictionary_en_us_es_es_COPY) — ta korak izvedite samo, če želite ohraniti trenutne prevode','Remove the trouble tables by executing the DROP function on them'=>'Odstranite težavne tabele z izvedbo funkcije DROP na njih','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Pojdite v Nastavitve -> TranslatePress -> zavihek Splošno in shranite nastavitve. S tem boste regenerirali tabele z uporabo trenutnega strežnika SQL.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopirajte ustrezno vsebino iz podvojenih tabel (npr. trp_dictionary_en_us_es_es_COPY) v novo generirano tabelo (trp_dictionary_en_us_es_es) — ta korak izvedite samo, če želite ohraniti trenutne prevode','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Preizkusite, če vse deluje. Če je šlo kaj narobe, lahko obnovite varnostno kopijo, ki ste jo ustvarili v prvem koraku. Preverite, ali se pri brskanju po vašem spletišču v prevedenem jeziku ne pojavljajo več napake. Poglejte časovne žige napak, da se prepričate, da ne vidite starih napak. Prikazanih je samo najnovejših 5 napak.','Plan C.'=>'Načrt C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Če vaša težava še vedno ni odpravljena, poskusite vprašati vašega gostitelja glede napak. Najpogostejši problem so manjkajoča dovoljenja za uporabnika SQL, kot je dovoljenje za ustvarjanje tabel.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Ni bilo mogoče namestiti. Poskusite znova v <a href="%s" >Nadzorna plošča vtičnikov.</a>','Active'=>'Aktivno','Permission denied.'=>'Dovoljenje zavrnjeno.','Invalid nonce.'=>'Neveljaven nonce.','Settings scope unknown.'=>'Neznan obseg nastavitev.','Legacy disabled.'=>'Zastarel način onemogočen.','Language Switcher'=>'Preklopnik jezika','Change language to %s'=>'Spremeni jezik v %s','Automatic Translation'=>'Samodejno prevajanje','DeepL'=>'DeepL','Unsupported languages'=>'Nepodprti jeziki','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Izbrani pogon za samodejno prevajanje ne podpira teh jezikov.<br>Strani v teh jezikih lahko še vedno ročno prevajate z urejevalnikom prevodov.','API key validation failed.'=>'Preverjanje API ključa ni uspelo.','API key verification was successful.'=>'Preverjanje API ključa je bilo uspešno.','Please enter your Google Translate key.'=>'Vnesite svoj Google Translate ključ.','Please enter your DeepL API key.'=>'Vnesite svoj DeepL API ključ.','Not TranslatePress onboarding page.'=>'To ni stran za uvod v TranslatePress.','Step %s does not exist'=>'Korak %s ne obstaja','Welcome'=>'Dobrodošli','Add Languages'=>'Dodaj jezike','Enable Addons'=>'Omogoči dodatke','Finalize'=>'Zaključi','Exit Setup'=>'Zapusti nastavitev','Upgrade'=>'Nadgradi','Nothing here'=>'Tukaj ni ničesar','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Vaša licenca za <strong>TranslatePress</strong> manjka ali je neveljavna. <br/>Prosimo, %1$sregistrirajte svojo kopijo%2$s, da omogočite samodejno prevajanje spletnega mesta prek TranslatePress AI, premium dodatke, samodejne posodobitve in podporo. Potrebujete licenčni ključ? %3$sKupite ga zdaj%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Vaša licenca za <strong>TranslatePress</strong> bo potekla %1$s. Prosimo, %2$sObnovite svojo licenco%3$s, da boste še naprej imeli dostop do samodejnih prevodov prek TP AI, premium dodatkov, prenosov izdelkov in samodejnih posodobitev. %4$sObnovi zdaj%5$s','Error: '=>'Napaka: ','Something went wrong, please try again.'=>'Nekaj je šlo narobe, poskusite znova.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Vaša licenca za <strong>TranslatePress</strong> je potekla. <br/>Prosimo, %1$sObnovite svojo licenco%2$s, da boste še naprej imeli dostop do samodejnih prevodov prek TranslatePress AI, premium dodatkov, prenosov izdelkov in samodejnih posodobitev. %3$sObnovi zdaj %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Neujemanje licenčnega ključa. Vnesena licenca se ne ujema z nameščeno različico <strong>%1$s</strong>. <br/>Preverite, ali ste za vašo licenco iz vašega %2$sTranslatePress Account%3$s namestili pravilno različico.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Če imate nameščen samo brezplačni vtičnik, vendar ste dodali plačano licenco, namestite plačani vtičnik iz vašega TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Dosegli ste omejitev aktivacije za vašo licenco <strong>%1$s</strong>. <br/>Upravljajte svoja aktivna spletišča iz %2$s vašega računa %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Vaša licenca je onemogočena za ta URL. Znova jo omogočite na <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Upravljanje spletišč.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Samodejno prevajanje %1$s zahteva aktivno licenco. Prosimo, %2$sobnovite%3$s svojo licenco ali kupite novo %4$stukaj%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Prosimo, %1$svnesite%2$s svoj licenčni ključ, da omogočite samodejno prevajanje %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Imate manj kot 5000 besed TranslatePress AI. Če želite še naprej samodejno prevajati svoje spletno mesto, %skupite dodatne AI besede s popustom prek svojega računa%s.',' Error: '=>' Napaka: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'To spletno mesto je že aktivirano z brezplačno licenco. Vsako spletno mesto lahko uporablja samo eno brezplačno licenco. Nadgradite na premium načrt za več besed TranslatePress AI iz %1$s vašega računa %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Nimate veljavne licence za <strong>TranslatePress</strong>. %1$sPridobite jo brezplačno%2$s, da pridobite dostop do TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NOVO:</strong> Dodatek <strong>Različna domena za vsak jezik</strong> je tu! Izboljšajte svoj globalni SEO in ustvarite lokalno izkušnjo z domenami za posamezne države, kot so .de ali .fr. Nadgradite na <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business ali Developer</a>, da dostopate do njega + več premium ugodnosti!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NOVO:</strong> Dodatek <strong>Različna domena za vsak jezik</strong> je tu! Izboljšajte svoj globalni SEO in ustvarite lokalno izkušnjo z domenami za posamezne države, kot so .de ali .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Več informacij</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Dnevna kvota znakov za strojno prevajanje je presežena. Preverite stran <strong>TranslatePress -> <a href="%s">Samodejno prevajanje</a></strong> za več informacij.','Marketing optin'=>'Marketing prijava','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Strinjajte se z obveščanjem o varnostnih in funkcionalnih posodobitvah ter z nesenzitivnim diagnostičnim sledenjem.','TranslatePress Preferred User Language'=>'TranslatePress želeni jezik uporabnika','Preferred language to navigate the site'=>'Želeni jezik za brskanje po spletni strani','The language is automatically set based by the last visited language by the user.'=>'Jezik se samodejno nastavi glede na zadnji obiskani jezik uporabnika.','Always use this language'=>'Vedno uporabi ta jezik','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Če označite to nastavitev, bo želeni jezik ostal takšen, kot je izbran zgoraj, brez možnosti spreminjanja na sprednjem delu spletišča.<br>Ta jezik bo uporabljen pri različnih operacijah, kot je pošiljanje e-pošte uporabniku.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Pozdravljeni! Kaže, da že nekaj časa uporabljate <strong>TranslatePress</strong> za prevajanje svoje spletne strani. Odlično! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Če si lahko vzamete nekaj trenutkov za ocenitev na WordPress.org, nam bo to veliko v pomoč (in povečalo mojo motivacijo).','~ Razvan, developer of TranslatePress'=>'~ Razvan, razvijalec TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Ocenite TranslatePress na strani vtičnika WordPress.org','Ok, I will gladly help!'=>'V redu, z veseljem pomagam!','No, thanks.'=>'Ne, hvala.','Full Language Names'=>'Polna imena jezikov','Short Language Names'=>'Kratka imena jezikov','Flags with Full Language Names'=>'Zastavice s polnimi imeni jezikov','Flags with Short Language Names'=>'Zastavice s kratkimi imeni jezikov','Only Flags'=>'Samo zastavice','Full Language Names No HTML'=>'Polna imena jezikov brez HTML','Bottom Right'=>'Spodaj desno','Bottom Left'=>'Spodaj levo','Top Right'=>'Zgoraj desno','Top Left'=>'Zgoraj levo','Dark'=>'Temno','Light'=>'Svetlo','Deactivate'=>'Deaktiviraj','Activate'=>'Aktiviraj','Invalid language code. Please try again.'=>'Neveljavna koda jezika. Poskusite znova.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Kode jezikov lahko vsebujejo le znake A-Z a-z 0-9 - _. Preverite kode jezikov v splošnih nastavitvah TranslatePress.','Error! Duplicate URL slug values.'=>'Napaka! Podvojene vrednosti URL slug-a.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Ne morete izbrati dveh jezikov, ki imata enako <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso kodo</a>, vendar različne formalnosti, ker bo to povzročilo podvojene <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang oznake</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Zaznan podvojen jezik.<br>Vsak jezik lahko dodate samo enkrat za natančno upravljanje prevodov.<br> Spremenite podvojeni vnos jezika in poskusite znova. ','Current Language'=>'Trenutni jezik','Opposite Language'=>'Nasprotni jezik','General'=>'Splošno','Translate Site'=>'Prevedi spletno mesto','Addons'=>'Dodatki','License'=>'Licenca','Settings'=>'Nastavitve','Activate License'=>'Aktiviraj licenco','Pro Features'=>'Pro funkcije','Need Help?'=>'Potrebujete pomoč?','Recent community discussions'=>'Nedavne razprave v skupnosti','Loading...'=>'Nalaganje...','Unable to load forum posts'=>'Ni mogoče naložiti objav foruma.','Ask a Question'=>'Zastavite vprašanje','View All Topics'=>'Ogled vseh tem','by'=>'od','Have a question?'=>'Imate vprašanje?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Poiščite pomoč neposredno pri razvijalcih vtičnika, predlagajte izboljšave ali delite povratne informacije!','Tip for faster help:'=>'Nasvet za hitrejšo pomoč:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Vključite, kaj ste poskusili, kaj ste pričakovali in kaj se je zgodilo. Posnetki zaslona pomagajo!','Toggle support chat'=>'Preklopi klepet za podporo','Ask the community'=>'Vprašajte skupnost','Close'=>'Zapri','Empty feed response'=>'Prazen odziv vira','Unable to parse feed'=>'Ni mogoče razčleniti vira','Just now'=>'Pravkar','%d hour ago'=>'pred %d uro' . "\0" . 'pred %d urama' . "\0" . 'pred %d urami' . "\0" . 'pred %d urami','%d day ago'=>'pred %d dnem' . "\0" . 'pred %d dnevoma' . "\0" . 'pred %d dnevi' . "\0" . 'pred %d dnevi','Source'=>'Vir','Srcset'=>'Srcset','Alt attribute'=>'Atribut alt','Title attribute'=>'Atribut title','Anchor link'=>'Sidrna povezava','Placeholder attribute'=>'Atribut placeholder','Submit attribute'=>'Atribut submit','Text'=>'Besedilo','Video Poster'=>'Poster videa','plural form'=>'Množinska oblika','one'=>'Ena','few'=>'Nekaj','many'=>'Veliko','other'=>'Druga','Saved'=>'Shranjeno','Save'=>'Shrani','Saving translation...'=>'Shranjevanje prevoda...','You have unsaved changes!'=>'Imate neshranjene spremembe!','Discard changes'=>'Zavrzi spremembe','Discard All'=>'Zavrzi vse','Loading Strings...'=>'Nalaganje nizov...','Select string to translate...'=>'Izberite niz za prevajanje...','Close Editor'=>'Zapri urejevalnik','From'=>'Iz','To'=>'V','Add Media'=>'Dodaj medij','Other languages'=>'Drugi jeziki','Context'=>'Kontekst','View Website As'=>'Ogled spletnega mesta kot','Available in our Pro Versions'=>'Na voljo v naših Pro različicah','Select or Upload Media'=>'Izberi ali naloži medij','Use this media'=>'Uporabi ta medij','Translate'=>'Prevedi','Translate entire block element'=>'Prevedi celoten element bloka','Split block to translate strings individually'=>'Razdeli blok za prevajanje posameznih nizov','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Shrani spremembe prevoda. Bližnjica: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Pomaknite se na naslednji niz v spustnem seznamu. Bližnjica: CTRL(⌘) + ALT + desna puščica','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Pomaknite se na prejšnji niz v spustnem seznamu. Bližnjica: CTRL(⌘) + ALT + leva puščica','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Zavrzi vse spremembe. Bližnjica: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Zavrzi spremembe v tem besedilnem polju. Če želiš zavreči spremembe v vseh besedilnih poljih, uporabi bližnjico: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Skrij namig','Quick Intro'=>'Kratek uvod','Are you sure you want to split this phrase into smaller parts?'=>'Ali ste prepričani, da želite razdeliti ta izraz na manjše dele?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Ta niz še ni pripravljen za prevod.<br>Poskusite znova čez trenutek...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Da bo ta možnost delovala, posodobite razširitev Browse as other role na najnovejšo različico.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Za prevajanje slug-ov posodobite dodatek SEO Pack na najnovejšo različico.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Nov jezik lahko dodate v <a href="%s">Nastavitve->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Vendar lahko še vedno uporabite TranslatePress za <strong style="background: #f5fb9d;">spreminjanje nizov Gettext</strong>, ki so na voljo na vaši strani.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Nizi, ki jih je ustvaril uporabnik, se ne morejo spreminjati, le tisti iz tem in vtičnikov.','Extra Translation Features'=>'Dodatne funkcije prevajanja','Support for 130+ Extra Languages'=>'Podpora za 130+ dodatnih jezikov','Access to TranslatePress AI'=>'Dostop do TranslatePress AI','Translate SEO Title, Description, Slug'=>'Prevedi SEO naslov, opis in slug','Publish only when translation is complete'=>'Objavi šele, ko je prevod dokončan','Translate by Browsing as User Role'=>'Prevedi z brskanjem kot uporabniška vloga','Different Menu Items for each Language'=>'Različni elementi menija za vsak jezik','Automatic User Language Detection'=>'Samodejno zaznavanje jezika uporabnika','Upgrade to PRO'=>'Nadgradi na PRO','Upgrade to PRO with our biggest discount of the year!'=>'Nadgradi na PRO z našim največjim popustom v letu!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Ta črni petek pridobi dostop do teh funkcij in več za delček cene:','No available suggestions'=>'Ni razpoložljivih predlogov','Suggestions from translation memory'=>'Predlogi iz prevodnega pomnilnika','Click to Copy'=>'Kliknite za kopiranje','Human Translation'=>'Človeški prevod','Machine Translation'=>'Strojni prevod','Text on this page is %s% translated into all languages.'=>'Besedilo na tej strani je %s % prevedeno v vse jezike.','%1$s% of text on this page is translated into %2$s.'=>'%1$s % besedila na tej strani je prevedeno v %2$s.','This page is %1$s% translated into %2$s.'=>'Ta stran je %1$s % prevedena v %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Slug, ki ga poskušate urediti, je prisoten v drugih vrstah slug-ov:%s. Urejanje bo zamenjalo vsako pojavitev, ne glede na trenutno vrsto.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Premaknite kazalec nad katero koli besedilo na strani, kliknite %s,<br> nato spremenite prevod v stranski vrstici.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Ne pozabite shraniti prevoda. Uporabite tipkovnično bližnjico CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Preklopite jezik, da vidite spremembe prevoda neposredno na strani.','Search for any text in this page in the dropdown.'=>'Poiščite katero koli besedilo na tej strani v spustnem meniju.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Vaša %s licenca je <span class="trp-license-status-emphasized">potekla</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Obnovite licenco, da še naprej prejemate dostop do TranslatePress AI, premium dodatkov, samodejnih posodobitev in podpore.','Renew Now'=>'Obnovi zdaj','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Ta črni petek obnovite licenco po posebni ceni</strong>, da še naprej prejemate dostop do prenosov izdelkov, samodejnih posodobitev in podpore.','Get Deal'=>'Izkoristi ponudbo','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Vaša %s licenca je bila <span class="trp-license-status-emphasized">povrnjena</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Kupite novo licenco, da še naprej prejemate dostop do TranslatePress AI, premium dodatkov, samodejnih posodobitev in podpore.','Purchase a new license'=>'Kupite novo licenco','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Vaša %s licenca je <span class="trp-license-status-emphasized">manjkajoča ali neveljavna</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Vnesite veljavno licenco za dostop do TranslatePress AI, premium dodatkov, samodejnih posodobitev in podpore. Potrebujete licenčni ključ? %1$sKupite ga zdaj%2$s','Enter a valid license'=>'Vnesite veljavno licenco','Slugs'=>'Slugi','Meta Information'=>'Meta informacije','String List'=>'Seznam nizov','Gettext Strings'=>'Gettext nizi','Images'=>'Slike','Videos'=>'Videoposnetki','Audios'=>'Zvočni posnetki','Dynamically Added Strings'=>'Dinamično dodani nizi','Translation Editor'=>'Urejevalnik prevodov','Edit translations by visually selecting them on each site page'=>'Urejajte prevode tako, da jih vizualno izberete na vsaki strani spletišča.','String Translation'=>'Prevajanje niza','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Urejanje prevodov URL slug-a, vtičnikov in tem (e-pošta, obrazci itd.)','Current User'=>'Trenutni uporabnik','Logged Out'=>'Odjavljeni','Translate Page'=>'Prevedi stran','Add a New Language'=>'Dodaj nov jezik','Get a Free AI License'=>'Pridobite brezplačno AI licenco','Your License is Invalid'=>'Vaša licenca je neveljavna','Get More AI Words (%d left)'=>'Pridobite več AI besed (%d preostalo)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Odpre objavo v urejevalniku prevodov. Objava mora biti predhodno shranjena kot osnutek ali objavljena.','Security check'=>'Varnostna preveritev','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Opozorilo:</strong> Nekateri nizi vsebujejo morda napačno kodirane znake. To lahko pokvari poizvedbe, zaradi česar se stran v živem načinu prikaže neprevedena. Razmislite o pregledu naslednjih nizov ali načina njihovega izpisa.','TranslatePress data update'=>'Posodobitev podatkov TranslatePress','We need to update your translations database to the latest version.'=>'Posodobiti moramo vašo bazo podatkov prevodov na najnovejšo različico.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Posodobitev bo omogočila urejanje prevodov lokaliziranega besedila iz vtičnikov in teme. Obstoječi prevod bo še vedno deloval kot pričakovano.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'POMEMBNO: Močno priporočamo, da najprej ustvarite varnostno kopijo baze podatkov!
Ali ste prepričani, da želite nadaljevati?','Run the updater'=>'Zaženi posodobitev','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Posodobitev bo omogočila urejanje prevodov polžev. Obstoječi prevod bo še vedno deloval kot pričakovano.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Prosimo, aktivirajte dodatek SEO v razdelku<br/>WordPress -> Nastavitve -> TranslatePress -> Dodatki','Go to Addons'=>'Pojdi v Dodatke','The SEO Pack add-on allows translation of all the URL slugs:'=>'Dodatek SEO Pack omogoča prevod vseh polžev URL:','Taxonomy slugs'=>'Polži taksonomij','Term slugs'=>'Polži pojmov','Post slugs (this includes pages and custom post types)'=>'Polži prispevkov (to vključuje strani in prilagojene vrste vsebine)','Post type base slugs'=>'Osnovni polži vrst vsebine','WooCommerce slugs'=>'Polži WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Dodatek SEO Pack je na voljo z vsemi premium različicami vtičnika.','Upgrade to Pro'=>'Nadgradi na Pro','Description'=>'Opis','Article Section'=>'Razdelek članka','Article Tag'=>'Oznaka članka','OG Title'=>'OG naslov','OG Site Name'=>'OG ime spletišča','OG Description'=>'OG opis','OG Image Alt'=>'OG alt slike','Twitter Title'=>'Twitter naslov','Twitter Description'=>'Twitter opis','Twitter Image Alt'=>'Twitter alt slike','Page Title'=>'Naslov strani','Dublin Core Title'=>'Dublin Core naslov','Dublin Core Description'=>'Dublin Core opis','OG Image'=>'OG slika','OG Image Secure URL'=>'OG varen URL slike','Twitter Image'=>'Twitter slika','Removing cdata dictionary strings for language %s...'=>'Odstranjevanje nizov slovarja cdata za jezik %s...','Removing untranslated dictionary links for language %s...'=>'Odstranjevanje neprevedenih povezav slovarja za jezik %s...','Removing duplicated gettext strings for language %s...'=>'Odstranjevanje podvojenih nizov Gettext za jezik %s...','Removing duplicated dictionary strings for language %s...'=>'Odstranjevanje podvojenih nizov slovarja za jezik %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Odstranjevanje neprevedenih nizov slovarja, za katere je na voljo prevod za jezik %s...','Inserting original strings for language %s...'=>'Vstavljanje izvornih nizov za jezik %s...','Cleaning original strings table for language %s...'=>'Čiščenje tabele izvornih nizov za jezik %s...','Updating original string ids for language %s...'=>'Posodabljanje ID-jev izvornih nizov za jezik %s...','Regenerating original meta table for language %s...'=>'Ponovno generiranje tabele izvirnih meta podatkov za jezik %s...','Cleaning original meta table for language %s...'=>'Čiščenje tabele izvirnih meta podatkov za jezik %s...','Replacing original id NULL with value for language %s...'=>'Zamenjava vrednosti NULL izvirnega ID-ja z vrednostjo za jezik %s...','Inserting gettext original strings for language %s...'=>'Vstavljanje izvornih nizov Gettext za jezik %s...','Cleaning gettext original strings table for language %s...'=>'Čiščenje tabele izvornih nizov Gettext za jezik %s...','Updating gettext original string ids for language %s...'=>'Posodabljanje ID-jev izvornih nizov Gettext za jezik %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Preselitev polžev taksonomij in osnovnih polžev vrst vsebine v novo strukturo tabele...','Migrating post slugs to new table structure for language %s...'=>'Preselitev polžev prispevkov v novo strukturo tabele za jezik %s...','Migrating term slugs to new table structure for language %s...'=>'Preseljevanje slugov izrazov v novo strukturo tabel za jezik %s...','Finishing up...'=>'Zaključevanje...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Optimizacija podatkovne zbirke ni bila uspešno zaključena. Priporočamo obnovitev izvirne podatkovne zbirke ali <a href="%s">ponovni poskus.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Posodobitev prekinjena! Vaš uporabniški račun nima potrebnih pravic za izvajanje posodobitev podatkovne zbirke.','Update aborted! Invalid nonce.'=>'Posodobitev prekinjena! Neveljaven nonce.','Update aborted! Incorrect action.'=>'Posodobitev prekinjena! Nepravilno dejanje.','Update aborted! Incorrect language code.'=>'Posodobitev prekinjena! Nepravilna koda jezika.','Updating database to version %s+'=>'Posodabljanje zbirke podatkov na različico %s+','Processing table for language %s...'=>'Obdelovanje tabele za jezik %s...','Back to TranslatePress Settings'=>'Nazaj na nastavitve TranslatePress','Successfully updated database!'=>'Zbirka podatkov je bila uspešno posodobljena!',' done.'=>' opravljeno.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Vsi posamezni vtičniki dodatkov TranslatePress <a href="%1$s" target="_blank">so bili ukinjeni</a> in so zdaj vključeni v premium različice Personal, Business in Developer programa TranslatePress. Prijavite se v svojo <a href="%2$s" target="_blank">stran računa</a>, prenesite novo premium različico in jo namestite. Nastavitve vaših posameznih dodatkov bodo prenesene.','Brand-new Language Switcher Settings are here!'=>'Nove nastavitve preklopnika jezika so tukaj!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Raziskujte predpripravljene predloge, preklapljajte barve, sloge zastavic, razmike, postavitve in še več. Z uporabo predogleda v živo v nekaj sekundah izpopolnite svoj preklopnik.','Start customizing'=>'Začnite prilagajati','Read documentation'=>'Preberite dokumentacijo','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> zahteva <strong><a href="http://php.net/manual/en/book.mbstring.php">knjižnico PHP Multibyte String</a></strong>. Obrnite se na skrbnika strežnika, da jo namesti na vaš strežnik.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Zaznana omejitev dolgih poizvedb pri gostovanju WPEngine. Nekatere velike strani se lahko prikažejo neprevedene. Omejitev lahko odstranite z dodajanjem naslednjega v datoteko wp-config.php vašega spletišča: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Zastava po meri','The Language code of the added custom language cannot be empty.'=>'Koda jezika za dodani jezik po meri ne more biti prazna.','The Language code of the added custom language is invalid.'=>'Koda jezika za dodani jezik po meri je neveljavna.','The Automatic Translation Code of the added custom language is invalid.'=>'Koda samodejnega prevoda za dodani jezik po meri je neveljavna.','TranslatePress Add-ons'=>'Dodatki za TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Najprej morate kupiti to različico, da boste imeli dostop do dodatka %1$stukaj%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Najprej %1$svnesite licenčni%2$s ključ, da aktivirate ta dodatek.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Potrebujete aktivno licenco za dostop do dodatka. Podaljšajte jo ali kupite novo %1$stukaj%2$s.','Advanced Add-ons'=>'Napredni dodatki','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Ti dodatki razširjajo vaš vtičnik za prevajanje in so na voljo v paketih Developer, Business in Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Legacy)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Podpora SEO za slug strani, naslov strani, opis ter informacije družbenega grafa za Facebook in Twitter. Atribut lang v HTML je pravilno nastavljen.','Multiple Languages'=>'Več jezikov','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Dodajte toliko jezikov, kot jih potrebujete, da bo vaš projekt globalen. Jezik objavite šele, ko so vsi prevodi končani.','Pro Add-ons'=>'Pro dodatki','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Ti dodatki razširjajo vaš vtičnik za prevajanje in so na voljo v paketih Business in Developer.','DeepL Automatic Translation'=>'Samodejno prevajanje DeepL','Automatically translate your website through the DeepL API.'=>'Samodejno prevedite svoje spletno mesto prek API-ja DeepL.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Obiskovalce pozove k preklopu na želeni jezik na podlagi nastavitev brskalnika ali naslova IP ter si zapomni zadnji obiskani jezik.','Translator Accounts'=>'Računi prevajalcev','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Ustvarite račune prevajalcev za nove uporabnike ali dovolite obstoječim uporabnikom, ki niso skrbniki, da prevajajo vaše spletno mesto.','Browse As User Role'=>'Brskanje kot uporabniška vloga','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Po svojem spletnem mestu brskajte tako, kot bi to počela določena uporabniška vloga. Zelo uporabno za dinamične vsebine ali skrite vsebine, ki se prikažejo določenim uporabnikom.','Navigation Based on Language'=>'Navigacija na podlagi jezika','Configure different menu items for different languages.'=>'Nastavite različne elemente menija za različne jezike.','Different Domain per Language'=>'Različna domena za vsak jezik','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Povežite ločene domene ali poddomene z vsako od svojih prevedenih različic. Utrdite lokalno identiteto svoje blagovne znamke in izboljšajte SEO učinkovitost za vsak jezik, ki ga podpirate.','Recommended Plugins'=>'Priporočeni vtičniki','A short list of plugins you can use to extend your website.'=>'Kratek seznam vtičnikov, ki jih lahko uporabite za razširitev svojega spletnega mesta.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Zajemite več uporabniških podatkov v obrazcu za registracijo s pomočjo polj za uporabniške profile po meri v Profile Builder in/ali dodajte postopek potrditve e-pošte za preverjanje računov svojih strank.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Sprejmite plačila uporabnikov, ustvarite naročniške načrte in omejite vsebino na svojem članskem spletnem mestu.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Ustvarite avtomatizacije in potek dela brez kode na svojem WordPress spletnem mestu. Preprosto povežite svoje vtičnike, spletna mesta in aplikacije med seboj.','Save Changes'=>'Shrani spremembe','TranslatePress Errors'=>'Napake TranslatePress','There are no logged errors.'=>'Ni zabeleženih napak.','Change language'=>'Spremeni jezik','Website language selector'=>'Izbirnik jezika spletnega mesta','WordPress Translation Plugin'=>'Vtičnik za prevajanje WordPress','Available languages'=>'Razpoložljivi jeziki','Language Switcher update notice'=>'Obvestilo o posodobitvi izbirnika jezika','Legacy language switcher is currently enabled'=>'Stari izbirnik jezika je trenutno omogočen','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Nadgradili smo izbirnik za bogatejše prilagajanje in boljšo uporabniško izkušnjo.<br>Za uporabo novega konfiguratorja izklopite <strong>Naloži stari izbirnik jezika</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Opomba: Kadarkoli se lahko vrnete iz <strong>Napredne nastavitve → <a href="%s">Odpravljanje težav</a></strong>.','Enable the new switcher'=>'Omogoči nov preklopnik','Your License Key is valid.'=>'Licenčni ključ je veljaven.','Your License Key is invalid.'=>'Licenčni ključ je neveljaven.','Your License has expired.'=>'Licenca je potekla.','Deactivate License'=>'Deaktiviraj licenco','Add a license key'=>'Dodaj licenčni ključ','License Key'=>'Licenčni ključ','Manage your license in your %1$s.'=>'Upravljaj svojo licenco v %1$s.','Account Page'=>'Stran računa','Don’t have a TranslatePress AI License Key?'=>'Nimaš licenčnega ključa za TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Enega lahko pridobiš %1$sbrezplačno%2$s z ustvarjanjem brezplačnega računa. Vključuje:','Access to TranslatePress AI for instant automatic translations'=>'Dostop do TranslatePress AI za takojšnje samodejne prevode','2000 AI words to translate automatically'=>'2000 AI besed za samodejno prevajanje','Get a free License Today'=>'Pridobi brezplačno licenco danes','Debug Information'=>'Podatki za razhroščevanje','Debug Data for License Checking'=>'Podatki za razhroščevanje pri preverjanju licence','Debug Data for License Activation'=>'Podatki za razhroščevanje pri aktivaciji licence','Get more AI words and unlock all features with TranslatePress Pro.'=>'Pridobi več AI besed in odkleni vse funkcije z TranslatePress Pro.','Upgrade now ↗'=>'Nadgradi zdaj ↗','Already purchased a Premium version?'=>'Ali ste že kupili premium različico?','Go to your %1$s'=>'Pojdite na svoj %1$s','TranslatePress.com Account'=>'Račun TranslatePress.com','Download & Install the Pro plugin'=>'Prenesite & namestite Pro vtičnik','Learn More'=>'Več informacij','Get a translation volume estimate with a detailed breakdown per page'=>'Pridobite oceno obsega prevoda s podrobnim razčlenjevanjem po straneh','Find how many translatable words are on your website'=>'Ugotovite, koliko prevedljivih besed je na vaši spletni strani','Enable Automatic Translation'=>'Omogočite samodejno prevajanje','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Za uporabo <strong>DeepL</strong> za samodejno prevajanje aktivirajte ta Pro dodatek v <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'<strong>DeepL</strong> samodejno prevajanje je na voljo kot <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Z nadgradnjo boste pridobili dostop do vseh plačljivih dodatkov, premium podpore ter s tem pomagali financirati prihodnji razvoj TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Upoštevajte, da je uporaba DeepL API plačljiva posebej. Glejte <a href="https://www.deepl.com/pro.html#developer">informacije o cenah DeepL</a>.','TranslatePress Pro Add-ons'=>'Dodatki TranslatePress Pro','Test API credentials'=>'Preizkusite API poverilnice','Check if the selected translation engine is configured correctly.'=>'Preverite, ali je izbrani prevajalni motor pravilno konfiguriran.','Alternative Engines'=>'Alternativni motorji','Switch to TranslatePress AI'=>'Preklopite na TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Integrirajte strojno prevajanje neposredno v svojo WordPress spletno stran.','More info'=>'Več informacij','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Izberite motor, ki ga želite uporabljati, da bi %1$s samodejno prevajali svojo spletno stran.','Automatic Translation Settings'=>'Nastavitve samodejnega prevajanja','AI Words Low Notification'=>'Obvestilo o nizkem številu AI besed','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Prejmite e-poštno obvestilo, ko število besed TranslatePress AI pade pod določeno mejo.','This feature is only available when using the TranslatePress AI translation engine.'=>'Ta funkcija je na voljo le pri uporabi prevajalskega pogona TranslatePress AI.','Notification Email'=>'E-pošta za obvestila','The email address where the low AI words notification will be sent.'=>'E-poštni naslov, kamor bo poslano obvestilo o nizkem številu AI besed.','Word Threshold'=>'Prag besed','words'=>'besed','You will be notified when remaining AI words drop below this number.'=>'Obveščeni boste, ko bo preostalo število AI besed padlo pod to številko.','Automatically Translate Slugs'=>'Samodejno prevedi slugove','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Generiraj samodejne prevode slugov za prispevke, strani in prilagojene vrste prispevkov.<br/>Slugi bodo samodejno prevedeni od druge osvežitve vsake strani naprej.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Ta funkcija je na voljo le v plačljivi različici. Nadgradi TranslatePress in odkleni več premium funkcij.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Zahteva nameščen in aktiviran <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">dodatek SEO Pack</a>.','Upgrade now'=>'Nadgradi zdaj','Block Crawlers'=>'Blokiraj pajke','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Prepreči pajkom sprožanje samodejnih prevodov na vaši spletni strani.<br>To ne bo preprečilo pajkom dostopa do strani tega spletišča.','Limit machine translation / characters per day'=>'Omejitev strojnega prevajanja / znakov na dan','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Dodajte omejitev števila samodejno prevedenih znakov, da boste lažje načrtovali proračun projekta.','characters per day'=>'znakov na dan','Today\'s Character Count: '=>'Današnje število znakov: ','Log machine translation queries.'=>'Beleži poizvedbe strojnega prevajanja.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Omogočite samo za namene testiranja. Lahko vpliva na zmogljivost.<br>Vsi zapisi so shranjeni v tabeli podatkovne baze wp_trp_machine_translation_log. Uporabite vtičnik, kot je <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a>, za brskanje po dnevnikih ali neposredno iz vašega upravitelja podatkovnih baz (PHPMyAdmin, itd.)','Test API Credentials'=>'Preizkusi poverilnice API','HTTP Referrer: '=>'HTTP napotnik: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Uporabite ta HTTP napotnik, če API omogoča omejitev uporabe ključa prek svoje nadzorne plošče.','Response'=>'Odgovor','Response Body'=>'Telo odgovora','Entire Response From wp_remote_get():'=>'Celoten odgovor iz wp_remote_get():','All Languages'=>'Vsi jeziki','Select the languages you wish to make your website available in.'=>'Izberite jezike, v katerih želite, da je vaše spletišče na voljo.','Formality'=>'Formalnost','Code'=>'Koda','Slug'=>'Slug','Default'=>'Privzeto','Formal'=>'Formalno','Informal'=>'Neformalno','Language'=>'Jezik','This language does not support formality. '=>'Ta jezik ne podpira formalnosti. ','Are you sure you want to remove this language?'=>'Ali ste prepričani, da želite odstraniti ta jezik?','Custom Languages'=>'Jeziki po meri','To Add more languages activate the Multiple Languages Addon'=>'Za dodajanje več jezikov aktivirajte dodatek Multiple Languages','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Za dodajanje več jezikov potrebujete aktivno licenco. Preverite v svojem %1$sračunu%2$s, ali je vaša licenca veljavna.','Please %1$senter your license%2$s key first to add more languages.'=>'Najprej %1$svnesite licenčni%2$s ključ, da boste lahko dodajali več jezikov.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Dodajanje več kot dveh jezikov je plačljiva funkcija. Nadgradite TranslatePress in odklenite več premium funkcij.','Website Languages'=>'Jeziki spletnega mesta','Default Language'=>'Privzeti jezik','Select the language your content is written in.'=>'Izberite jezik, v katerem je napisana vaša vsebina.','WARNING. Changing the default language will invalidate existing translations.'=>'OPOZORILO. Sprememba privzetega jezika bo razveljavila obstoječe prevode.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Tudi sprememba iz en_US v en_GB, saj sta obravnavana kot dva različna jezika.','In most cases changing the default flag is all it is needed: '=>'V večini primerov je dovolj, da spremenite privzeto zastavico: ','replace the default flag'=>'zamenjajte privzeto zastavico','Re-run Setup Wizard'=>'Znova zaženi čarovnika za nastavitev','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Čarovnik za nastavitev vam omogoča hitro nastavitev TranslatePressa. Zaženete ga lahko kadar koli.','Language Settings'=>'Nastavitve jezikov','Use Native language name'=>'Uporabi izvirno ime jezika','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Označite, če želite prikazati jezike v njihovih izvirnih imenih. V nasprotnem primeru bodo jeziki prikazani v angleščini.','Use a subdirectory for the default language'=>'Uporabi podmapo za privzeti jezik','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Označite, če želite dodati podmapo v URL za privzeti jezik.</br>S potrditvijo te možnosti bo privzeti jezik, ki ga vidijo obiskovalci spletnega mesta, postal prvi na seznamu "Vsi jeziki".','Force language in custom links'=>'Vsili jezik v povezavah po meri','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Izberite Da, če želite, da povezave po meri brez jezikovnega kodiranja ohranijo trenutno izbrani jezik.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Uporabite shortcode na kateri koli strani ali pripomočku.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Dodate lahko tudi <a href="%s" title="Language Switcher Block Documentation">blok za preklapljanje jezikov</a> v urejevalniku WP Gutenberg.','Menu item'=>'Postavka menija','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Pojdite v  %1$s Videz -> Meniji%2$s, če želite dodati jezike v preklopnik jezikov v kateri koli meni.','Learn more in our documentation.'=>'Več informacij najdete v naši dokumentaciji.','Floating language selection'=>'Plavajoča izbira jezika','Add a floating dropdown that follows the user on every page.'=>'Dodajte plavajoč spustni seznam, ki uporabnika spremlja na vsaki strani.','Show "Powered by TranslatePress"'=>'Prikaži "Powered by TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Prikažite majhen napis "Powered by TranslatePress" v plavajočem preklopniku jezikov.','5 Days to Better Multilingual Websites'=>'5 dni do boljših večjezičnih spletnih mest','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sPridružite se našemu BREZPLAČNEMU & EKSKLUZIVNEMU tečaju za uvajanje%s in se naučite, kako povečati svoj večjezični promet, doseči mednarodne trge ter prihraniti čas & denar, medtem ko iz TranslatePress izvlečete največ!','Invalid email address'=>'Neveljaven e-poštni naslov','Your email'=>'Vaša e-pošta','Sign me up!'=>'Prijavite me!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Prijavite se z e-poštnim naslovom in prejmite 5-delni e-poštni vodnik, ki vam bo pomagal izkoristiti moč TranslatePress.','Dismiss email course notification'=>'Opusti obvestilo o e-poštnem tečaju','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hej %s,<br>Ne zamudite pomembne posodobitve - naročite se na obvestila o varnostnih in funkcionalnih posodobitvah ter neobčutljivo diagnostično sledenje.','Allow & Continue'=>'Dovoli & nadaljuj','Skip'=>'Preskoči','This will allow TranslatePress to:'=>'To bo TranslatePressu omogočilo:','Your profile overview'=>'Pregled vašega profila','Name and email address'=>'Ime in e-poštni naslov','Admin Notices'=>'Skrbniška obvestila','Updates, announcements, marketing, no spam'=>'Posodobitve, obvestila, trženje, brez neželene pošte','Plugin status & settings'=>'Stanje vtičnika in nastavitve','Active, Deactivated, installed version and settings'=>'Aktiven, deaktiviran, nameščena različica in nastavitve','Privacy Policy'=>'Politika zasebnosti','Terms of Service'=>'Pogoji storitve','Support'=>'Podpora','Documentation'=>'Dokumentacija','Add Extra AI Words'=>'Dodaj dodatne AI besede','Optimize TranslatePress database tables'=>'Optimiziraj tabele podatkovne baze TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>POMEMBNA OPOMBA:</strong> Pred izvedbo tega dejanja je zelo priporočljivo najprej ustvariti varnostno kopijo podatkovne baze.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'POMEMBNO: Zelo priporočljivo je najprej ustvariti varnostno kopijo podatkovne baze!! Ali ste prepričani, da želite nadaljevati?','Operations to perform'=>'Operacije za izvedbo','Remove CDATA for original and dictionary strings'=>'Odstrani CDATA za izvirne in slovarske nize','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Odstrani CDATA iz tabel trp_original_strings in trp_dictionary_*.<br>Ta vrsta vsebine ne bi smela biti zaznana s strani TranslatePress. Morda je bila vnesena v podatkovno bazo v starejših različicah vtičnika.','Remove untranslated links from dictionary tables'=>'Odstrani neprevedene povezave iz slovarskih tabel','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Odstrani neprevedene povezave in slike iz vseh tabel trp_dictionary_*. Te tabele vsebujejo prevode za nize, ki jih je vnesel uporabnik, kot so vsebina prispevka, naslov prispevka, meniji itd.','Remove duplicate rows for gettext strings'=>'Odstrani podvojene vrstice za nize Gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Odstrani podvojene vrstice iz vseh tabel trp_gettext_*. Te tabele vsebujejo prevode za nize tem in vtičnikov.','Remove duplicate rows for dictionary strings'=>'Odstrani podvojene vrstice za slovarske nize','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Odstrani podvojene vrstice iz vseh tabel trp_dictionary_*. Te tabele vsebujejo prevode za nize, ki jih je vnesel uporabnik, kot so vsebina prispevka, naslov prispevka, meniji itd.','Remove duplicate rows for original dictionary strings'=>'Odstrani podvojene vrstice za izvirne slovarske nize','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Odstrani podvojene vrstice iz tabele trp_original_strings. Ta tabela vsebuje nize v privzetem jeziku brez kakršnihkoli prevodov.<br>Prav tako se regenerira tabela trp_original_meta, ki vsebuje meta informacije, ki se nanašajo na ID nadrejenega prispevka.<br>Takšne podvojene vrstice se lahko pojavijo v izjemnih situacijah nepričakovanega vedenja.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Zamenjaj nize Gettext, ki imajo izvirni ID NULL, s pravilnimi izvirnimi ID-ji','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Odpravi težavo v robnem primeru, ko nekateri nizi Gettext imajo izvirni ID nepravilno nastavljen na NULL, kar povzroča težave v prevajalskem urejevalniku.<br>Ta operacija popravi izvirne ID-je v tabelah trp_gettext_*.<br>To možnost označite le, če ste naleteli na težavo v prevajalskem urejevalniku, kjer klik na zeleni svinčnik ni prikazal niza Gettext za prevod v levi stranski vrstici.<br>V nasprotnem primeru pustite to možnost neoznačeno, saj je to zahtevna operacija.','Optimize Database'=>'Optimiziraj bazo podatkov','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Posodabljanje tabel TranslatePress. Prosimo, pustite to okno odprto.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Neaktivni jeziki bodo še vedno vidni in aktivni za administratorja. Za druge uporabnike ne bodo vidni v izbirnikih jezikov in tudi dostopni ne bodo.','unknown'=>'neznano','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Dodatek Extra Languages</strong> zahteva različico TranslatePress %1$s ali višje. Trenutno uporabljate različico %2$s. Posodobite TranslatePress, da omogočite to funkcijo.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Samodejne in ročne spremembe prevodov slugov, opravljene, ko je bil aktiven <strong>TranslatePress - Multilingual</strong> 2.8.4, so morale biti odstranjene zaradi nekaterih težav s to različico. Vsi prevodi slugov iz obdobja pred to različico so zdaj v uporabi. Hvala za razumevanje!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Če jih nujno potrebujete, so odstranjeni prevodi na voljo v tabelah trp_slug_original_obsolete in trp_slug_translation_obsolete.','View Docs'=>'Ogled dokumentacije','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Dodeli različne domene ali poddomene vsakemu jeziku. Ko obiskovalci dostopijo do teh domen, TranslatePress neposredno naloži ustrezen jezikovni prevod brez preusmeritve.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Primer: %1$s za angleščino, %2$s za španščino, %3$s za francoščino.','Before enabling:'=>'Pred omogočitvijo:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Poskrbite, da so vaše domene registrirane, usmerjene na vaš strežnik in da imajo konfigurirana SSL potrdila.','Domain'=>'Domena','Map this language to a different domain or sub-domain.'=>'Preslikajte ta jezik na drugo domeno ali poddomeno.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Predizpolni s trenutno domeno','Check DNS'=>'Preveri DNS','Checking DNS...'=>'Preverjanje DNS...','DNS is correctly configured!'=>'DNS je pravilno konfiguriran!','DNS check failed. Please verify your domain configuration.'=>'Preverjanje DNS ni uspelo. Preverite konfiguracijo domene.','This domain is already assigned to another language.'=>'Ta domena je že dodeljena drugemu jeziku.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Razširitev za različno domeno na jezik</strong> zahteva TranslatePress različice %1$s ali višjo. Trenutno uporabljate različico %2$s. Posodobite TranslatePress, da omogočite to funkcijo.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Opomba: Ta možnost je onemogočena, ko je aktivna razširitev za različno domeno na jezik.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Različna domena na jezik: Domena je obvezna, ko je preslikava domen omogočena. Stikalo je bilo onemogočeno za jezike s praznimi domenami.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Različna domena na jezik: Ista domena ne more biti dodeljena več jezikom. Stikalo je bilo onemogočeno za podvojene domene.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Različna domena na jezik: Domena jezika ne more biti enaka glavnemu URL-ju spletišča. Stikalo je bilo onemogočeno za ujemajočo se domeno.','Please enter a domain.'=>'Vnesite domeno.','Invalid domain format.'=>'Neveljavna oblika domene.','Could not reach domain: %s'=>'Domene ni bilo mogoče doseči: %s','Domain returned HTTP status %d.'=>'Domena je vrnila HTTP status %d.','Domain is reachable!'=>'Domena je dosegljiva!','Limit this menu item to the following languages'=>'Omeji ta element menija na naslednje jezike','Date format'=>'Format datuma','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Prilagodi oblikovanje datuma za vsak prevedeni jezik.<br/>Pustite prazno za privzeto nastavitev WP ali si oglejte več informacij <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">tukaj</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Za urejanje obstoječega jezika TranslatePress vnesite kodo jezika in izpolnite le stolpce, ki jih želite prepisati (npr. ime jezika, zastava).<br>Lahko dodate tudi nove jezike po meri. Ti bodo na voljo pod splošnimi nastavitvami, na seznamu vseh jezikov, kjer je mogoče urediti URL slug.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Za zastavo po meri najprej naložite sliko v medijsko knjižnico, nato prilepite URL.<br>Sprememba ali brisanje jezika po meri bo vplivala na prevode in URL-je spletnega mesta.<br>Koda jezika in ISO koda morata vsebovati samo abecedne vrednosti, številčne vrednosti, "-" in "_".<br>ISO kode najdete na <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO kode</a> in <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL ciljne kode</a>.','Language code'=>'Koda jezika','Language name'=>'Ime jezika','Native name'=>'Izvorno ime','ISO Code'=>'ISO koda','Flag URL'=>'URL zastave','Text RTL'=>'RTL besedilo','Custom language'=>'Jezik po meri','Disable dynamic translation'=>'Onemogoči dinamični prevod','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Onemogoči zaznavanje nizov, ki so prikazani dinamično z uporabo JavaScripta. <br/>Nizi, naloženi prek strežniškega klica AJAX, bodo še vedno prevedeni.','Disable translation for gettext strings'=>'Onemogoči prevajanje nizov Gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Gettext nizi so nizi, ki jih izpišejo teme in vtičniki. <br> Prevajanje teh vrst nizov prek TranslatePress je lahko nepotrebno, če so že prevedeni z uporabo sistema prevajalskih datotek .po/.mo.<br>Omogočitev te možnosti lahko v določenih primerih izboljša hitrost nalaganja strani vašega spletnega mesta. Slabost je, da teh prevodov gettext ni več mogoče urejati v TranslatePress, niti ni mogoče samodejno prevajati teh nizov.','Gettext Strings translation is disabled'=>'Prevajanje Gettext nizov je onemogočeno','To enable it go to '=>'Za omogočitev pojdite na ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Napredne nastavitve->Razhroščevanje->Onemogoči prevajanje nizov Gettext',' and uncheck the Checkbox.'=>' in počistite potrditveno polje.','Dismiss'=>'Opusti','Exclude translated links from sitemap'=>'Izključi prevedene povezave iz sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Ne vključujte prevedenih povezav v sitemaps, ki jih ustvarjajo SEO vtičniki.<br/>Zahteva nameščen in aktiviran <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> dodatek SEO Pack</a>.','Disable post container tags for post title'=>'Onemogoči oznake vsebnika za naslov prispevka','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Onemogoči indeksiranje naslova prispevka v prevedenih jezikih.<br/>Uporabno, kadar naslov prispevka ne dovoli HTML-ja in se stran zaradi tega pokvari.','Disable post container tags for post content'=>'Onemogoči oznake vsebnika za vsebino prispevka','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Onemogoči indeksiranje vsebine prispevka v prevedenih jezikih.<br/>Uporabno, kadar vsebina prispevka ne dovoli HTML-ja in se stran zaradi tega pokvari.','Do not translate certain paths'=>'Ne prevajaj določenih poti','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Izberite, katere poti so lahko prevedene. Podpira nadomestni znak na koncu poti.<br>Na primer, da izključite https://example.com/some/path, lahko uporabite pravilo /some/path/ ali /some/*.<br>Vnesite vsako pravilo v svojo vrstico. Da izključite domačo stran, uporabite {home}.','Exclude Paths From Translation'=>'Izključi poti iz prevoda','Translate Only Certain Paths'=>'Prevedi samo določene poti','Enable the hreflang x-default tag for language:'=>'Omogoči oznako hreflang x-default za jezik:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Omogoči hreflang="x-default" za celoten jezik. Za več podrobnosti si oglejte dokumentacijo.','Translate numbers and numerals'=>'Prevedi številke in števnike','Enable translation of numbers ( e.g. phone numbers)'=>'Omogoči prevajanje številk ( npr. telefonske številke)','Selector'=>'Selektor','Exclude from dynamic translation'=>'Izključi iz dinamičnega prevajanja','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Ne prevajaj dinamično nizov, ki se nahajajo v HTML vozliščih, ki ustrezajo tem selektorjem.<br>Izključuje vse podrejene elemente HTML vozlišč, ki ustrezajo tem selektorjem, iz prevajanja z uporabo JavaScripta.<br/>Ti nizi bodo še vedno prevedeni na strežniški strani, če je to mogoče.','Gettext String'=>'Gettext niz','Exclude Gettext Strings'=>'Izključi Gettext nize','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Izključi te nize iz prevajanja kot Gettext nize s strani TranslatePress. Pustite domeno prazno, da se upošteva kateri koli Gettext niz.<br/>Še vedno jih je mogoče prevesti preko datotek po/mo.','Exclude selectors only from automatic translation'=>'Izključi izbirnike samo iz samodejnega prevoda','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Ne prevajaj samodejno nizov, ki se nahajajo v HTML vozliščih, ki ustrezajo tem selektorjem.<br>Izključuje vse podrejene elemente HTML vozlišč, ki ustrezajo tem selektorjem, iz samodejnega prevajanja.<br>Ročno prevajanje teh nizov je še vedno mogoče.','Exclude selectors from translation'=>'Izključi izbirnike iz prevoda','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Ne prevajaj nizov, ki se nahajajo v HTML vozliščih, ki ustrezajo tem selektorjem.<br>Izključuje vse podrejene elemente HTML vozlišč, ki ustrezajo tem selektorjem, iz prevajanja.<br>Tih nizov ni mogoče prevesti ročno niti samodejno.','String'=>'Niz','Exclude strings from automatic translation'=>'Izključi nize iz samodejnega prevajanja','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Ne prevajaj samodejno teh nizov (npr. imena, tehnične besede...)<br>Odstavki, ki vsebujejo te nize, bodo še vedno prevedeni, razen določenega dela.','Fix broken HTML'=>'Popravi pokvarjen HTML','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Splošen poskus popravila pokvarjenega ali manjkajočega HTML na prevedenih straneh.<br/>','Force slash at end of home url:'=>'Vsili poševnico na koncu domačega URL-ja:','Ads a slash at the end of the home_url() function'=>'Doda poševnico na konec funkcije home_url()','Show Both (recommended)'=>'Prikaži oba (priporočeno)','Remove Country Locale'=>'Odstrani državno lokalizacijo','Remove Region Independent Locale'=>'Odstrani splošno lokalizacijo','Remove duplicate hreflang'=>'Odstrani podvojene hreflang','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Izberite, katere oznake hreflang se bodo prikazovale na vašem spletnem mestu.<br/>Priporočamo prikaz obeh vrst oznak hreflang, kot to navaja <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">dokumentacija Google</a>.<br/>Odstranitev državne lokalizacije pri več državnih lokalizacijah istega jezika (npr. angleščina VB in angleščina ZDA) bo povzročila prikaz ene oznake hreflang s povezavo do le ene od regionalnih lokalizacij za ta jezik.','Default (example: en-US, fr-CA, etc.)'=>'Privzeto (primer: en-US, fr-CA, itd.)','Regional (example: en, fr, es, etc.)'=>'Regionalno (primer: en, fr, es, itd.)','HTML Lang Attribute Format'=>'Format atributa lang HTML','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Spremenite atribut lang oznake HTML v obliko, ki vključuje kodo države/regije ali ne. <br>V HTML naj bi se atribut lang (<html lang="en-US">)  uporabljal za  določitev jezika besedilne vsebine, tako da  lahko brskalnik pravilno prikaže ali obdela  vašo vsebino (npr. za  deljenje besed s pomišljajem, oblikovanje, preverjanje črkovanja, itd.).','Load legacy Language Switcher'=>'Naloži starejši izbirnik jezika','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Velja za vse vrste izbirnikov jezika (plavajoči, shortcode in meni). Ko je omogočeno, se bo spletno mesto vrnilo k uporabi izvirnega izbirnika jezika, konfiguriranega na zavihku Splošne nastavitve, in nadomestilo novo prilagodljivo različico. Vaše obstoječe nastavitve izbirnika bodo ostale shranjene, vendar bodo prezrte, dokler je ta možnost aktivna.','Load legacy SEO Pack Add-On'=>'Naloži starejši dodatek SEO Pack','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'V primeru, da nedavna migracija na novo prepisovanje slug povzroča težave, nastavite to na Da, da uporabite staro metodo <br> Prosimo, <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">odprite zahtevek za podporo</a> in nam sporočite težave, ki jih imate.','Manual Translation Only'=>'Samo ročno prevajanje','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress proaktivno pregleduje in shranjuje nize v podatkovno bazo, ko uporabniki dostopajo do prevedenih strani. <br>Ta nastavitev onemogoči to funkcionalnost in dovoli prevajanje ter shranjevanje nizov samo znotraj Urejevalnika prevodov. <br>Onemogoči tudi strojno prevajanje zunaj Urejevalnika prevodov, kar vam omogoča boljši nadzor nad porabo znakov, saj se prevajajo samo strani, ki jih obiščete v Urejevalniku prevodov.','Open language switcher only on click'=>'Odpiraj izbirnik jezika le ob kliku','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Odpiraj izbirnik jezika shortcode s klikom nanj namesto z lebdenjem.<br> Zapri ga s klikom nanj, kamorkoli drugam na zaslonu ali s pritiskom na tipko Escape. To bo vplivalo le na izbirnik jezika shortcode.','Show opposite language in the language switcher'=>'Prikaži nasprotni jezik v izbirniku jezika','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Pretvori izbirnik jezika v gumb, ki prikaže drugi razpoložljivi jezik, ne trenutnega.<br> Deluje le, ko sta natančno dva jezika, privzeti jezik in jezik prevoda.<br>To bo vplivalo tudi na izbirnik jezika shortcode in plavajoči izbirnik jezika.<br> Da to dosežete v izbirniku jezika v meniju, pojdite na Videz->Meni->Izbirnik jezika in izberite Nasprotni jezik.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Kliknite tukaj</a> za dostop do orodja za optimizacijo podatkovne baze.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Pomaga odstraniti morebitne podvojene prevode, počistiti nepotrebne podatke in popraviti morebitne težave z metapodatki.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Tukaj</a> si lahko ogledate zadnjih 5 SQL napak, povezanih s TranslatePress, če obstajajo.','Troubleshooting'=>'Odpravljanje težav','Exclude Gettext strings'=>'Izključi Gettext nize','Debug'=>'Razhroščevanje','Custom languages'=>'Jeziki po meri','Miscellaneous options'=>'Razne možnosti','Exclude strings & pages'=>'Izključi nize & strani','Automatic Translation Memory'=>'Samodejni pomnilnik prevodov','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Uporabi enak prevod za podobno besedilo. Nizi morajo imeti 95 % podobnosti.<br>Pomaga preprečiti izgubo obstoječega prevoda pri popravljanju tipkarskih napak ali manjših prilagoditvah izvirnega besedila. <br>Če že obstaja prevod za zelo podoben izvirni niz, bo samodejno uporabljen za trenutni izvirni niz.<br>Ne deluje pri spreminjanju besedila, ki je del prevajalskega bloka, razen če je novo besedilo ročno združeno nazaj v prevajalski blok.<br>Vsak niz mora imeti najmanj 50 znakov.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'OPOZORILO: Ta funkcija lahko negativno vpliva na čase nalaganja strani v sekundarnih jezikih, zlasti pri velikih bazah podatkov (na primer spletna mesta z veliko stranmi ali izdelki). Če opazite počasno nalaganje, to onemogočite in poskusite znova.','Fix missing dynamic content'=>'Popravi manjkajočo dinamično vsebino','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Lahko pomaga popraviti manjkajočo vsebino, vstavljeno z JavaScriptom. <br> Za trenutek prikaže dinamično vstavljeno vsebino v izvirnem jeziku, preden je zahtevek za prevod zaključen.','Filter Gettext wrapping from post content and title'=>'Filtriraj Gettext ovoj iz vsebine in naslova prispevka','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtrira Gettext ovoj, kot je #!trpst#trp-gettext, iz vsebine in naslova posodobljenih prispevkov. Ne vpliva na prejšnjo vsebino prispevka. <br/><strong>Priporočamo varnostno kopijo podatkovne baze, preden to omogočite.</strong>','Filter Gettext wrapping from post meta'=>'Filtriraj Gettext ovoj iz meta podatkov prispevka','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtrira Gettext ovoj, kot je #!trpst#trp-gettext, iz posodobljenih meta podatkov prispevka. Ne vpliva na prejšnje meta podatke prispevka. <br/><strong>Priporočamo varnostno kopijo podatkovne baze, preden to omogočite.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Google Translate API ključ','Add your API Key here...'=>'Tukaj dodajte svoj API ključ...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Obiščite <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">to povezavo</a>, da vidite, kako nastaviti API ključ, <strong>nadzorovati stroške API</strong> in nastaviti omejitve HTTP referrerja.','Your HTTP referrer is: %s'=>'Vaš HTTP referrer je: %s','There was an error on the server processing your Google Translate key.'=>'Prišlo je do napake na strežniku pri obdelavi vašega ključa Google Translate.','There was an error with your Google Translate key.'=>'Prišlo je do napake z vašim ključem Google Translate.','Please check your TranslatePress license key.'=>'Preverite svoj licenčni ključ TranslatePress.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Za to spletno mesto ni zaznane aktivne licence.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Za omogočitev samodejnega prevoda z uporabo TranslatePress AI potrebujete licenčni ključ, ki ga pridobite z ustvaritvijo brezplačnega računa.','Create your Free Account'=>'Ustvarite brezplačni račun',' or '=>' ali ','Enter your license key'=>'Vnesite licenčni ključ',' Or %1$spurchase one here%2$s'=>' Ali %1$skuplite ga tukaj%2$s','Your free account includes: '=>'Vaš brezplačni račun vključuje: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Pridobite več AI besed in odklenite vse AI funkcije z TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Imate veljavno %s <strong>licenco</strong>.',' words remaining. '=>' preostalih besed. ','Recheck'=>'Ponovno preverite','Rechecking...'=>'Ponovno preverjanje...','Done.'=>'Končano.','Manage your license & quota on the %s'=>'Upravljajte svojo licenco in kvoto na %s','TranslatePress.com Account Page'=>'Stran računa TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'SEO podpora za slug strani, naslov strani, opis ter podatke družbenega grafa za Facebook in Twitter. Atribut HTML lang je pravilno nastavljen.','Enable Modules'=>'Omogočite module','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Omogočite module dodatkov za razširitev TranslatePress in izboljšanje funkcionalnosti vašega prevedenega spletišča.','More functionality with TranslatePress Pro.'=>'Več funkcionalnosti z TranslatePress Pro.','Already a Pro User?'=>'Ste že uporabnik Pro?','Activate License Key'=>'Aktivirajte licenčni ključ','This add-on is not available on your current plan.'=>'Ta dodatek ni na voljo v vašem trenutnem paketu.','Continue'=>'Nadaljuj','The link you followed has expired. Please reload the page and try again.'=>'Povezava, ki ste ji sledili, je potekla. Ponovno naložite stran in poskusite znova.','A valid license is required to enable Automatic Translation.'=>'Za omogočanje samodejnega prevajanja je potrebna veljavna licenca.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Vaš licenčni ključ je onemogočen za ta URL. Znova ga omogočite na <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Upravljanje mest.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Neskladje licenčnega ključa.</strong> Vnesena licenca se ne ujema z nameščeno različico TranslatePress.</p><p>Preverite, ali ste iz svojega TranslatePress računa namestili pravilno različico za vašo licenco.</p>','Automatically translate your website using TranslatePress AI.'=>'Samodejno prevedite svoje spletno mesto s TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'Za omogočanje samodejnega prevajanja s TranslatePress AI vnesite svoj licenčni ključ iz','your account.'=>'vašega računa.','Skip and continue with manual translation »'=>'Preskoči in nadaljuj z ročnim prevajanjem »','Get Your Free TranslatePress AI License'=>'Pridobite brezplačno licenco TranslatePress AI','Generate License'=>'Ustvari licenco','Creating a free account includes: '=>'Ustvarjanje brezplačnega računa vključuje: ','Are you a TranslatePress PRO user?'=>'Ali ste uporabnik TranslatePress PRO?','Install & Activate your pro plugin.'=>'Namestite in aktivirajte svoj pro vtičnik.','Skip this step'=>'Preskoči ta korak','The email address you added is incorrect.'=>'E-poštni naslov, ki ste ga dodali, je napačen.','Setup Complete'=>'Nastavitev je zaključena','You\'re ready to start translating!'=>'Pripravljeni ste, da začnete prevajati!','You have successfully set up TranslatePress for your website.'=>'Uspešno ste nastavili TranslatePress za svoje spletno mesto.','Receive '=>'Prejmite ','Yes, send me multilingual growth tips.'=>'Da, pošiljajte mi večjezične nasvete za rast.','Start translating'=>'Začnite prevajati','Sign Up and Start translating'=>'Prijavite se in začnite prevajati','Please upload a TranslatePress Pro plugin file.'=>'Naložite datoteko vtičnika TranslatePress Pro.','Upload error: '=>'Napaka pri nalaganju: ','Install failed: '=>'Namestitev ni uspela: ','Plugin installed, but entry file not found. '=>'Vtičnik je nameščen, vendar vhodne datoteke ni bilo mogoče najti. ','Activation error: '=>'Napaka pri aktivaciji: ','Invalid plugin specified.'=>'Naveden je neveljaven vtičnik.','Invalid action specified.'=>'Navedeno je neveljavno dejanje.','Plugin deactivation failed.'=>'Deaktivacija vtičnika ni uspela.','Plugin activation failed: '=>'Aktivacija vtičnika ni uspela: ','First, install and activate TranslatePress Pro'=>'Najprej namestite in aktivirajte TranslatePress Pro','Please upload the TranslatePress PRO zip archive from your'=>'Naložite arhiv zip TranslatePress PRO iz vašega','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'Namestite in aktivirajte','Installed Pro versions'=>'Nameščene različice Pro','« Go back'=>'« Nazaj','Activate License »'=>'Aktivirajte licenco »','You are trying to add an invalid additional language. Please select a valid option.'=>'Poskušate dodati neveljaven dodatni jezik. Izberite veljavno možnost.','Please add an additional language.'=>'Prosimo, dodajte dodatni jezik.','You are trying to add an invalid default language. Please select a valid option.'=>'Poskušate dodati neveljaven privzeti jezik. Izberite veljavno možnost.','You need to select a default language.'=>'Izbrati morate privzeti jezik.','Configure Site Languages'=>'Nastavi jezike spletišča','Select the default and additional languages for your website.'=>'Izberite privzeti in dodatne jezike za svoje spletišče.','You can edit your site languages at any point.'=>'Jezike spletišča lahko uredite kadar koli.','Additional Language'=>'Dodatni jezik','Choose a secondary language...'=>'Izberite drugi jezik...','Add Language'=>'Dodaj jezik','Choose a language...'=>'Izberite jezik...','Add more than two languages with TranslatePress Pro.'=>'Dodajte več kot dva jezika z TranslatePress Pro.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'Vaš licenčni ključ je onemogočen za ta URL. Znova ga omogočite na <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Upravljanje spletišč.','Add your License Key'=>'Dodajte svoj licenčni ključ','Add your License Key to unlock all premium features. Find the License Key in your'=>'Dodajte svoj licenčni ključ, da odklenete vse premium funkcije. Licenčni ključ najdete v svojem','Your license is valid and active.'=>'Vaša licenca je veljavna in aktivna.','« Go Back'=>'« Nazaj','Set up Language Switcher'=>'Nastavi preklopnik jezikov','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'Izberite slog preklopnika jezikov. Več načinov prikaza boste našli v nastavitvah vtičnika.','Displays a small language drop-down across your website, in a corner of your choosing.'=>'Prikazuje majhen jezikovni spustni meni po celotnem spletišču, v kotu po vaši izbiri.','Switcher Location'=>'Lokacija preklopnika','Apply a Template'=>'Uporabi predlogo','You can customize the design later'=>'Obliko lahko prilagodite pozneje','Default Template'=>'Privzeta predloga','Dark Template'=>'Temna predloga','Border Template'=>'Predloga z obrobo','Border'=>'Obroba','Transparent Template'=>'Prosojna predloga','Transparent'=>'Prosojna','Welcome to TranslatePress'=>'Dobrodošli v TranslatePress','Quick guided setup to configure TranslatePress in no time!'=>'Hitra vodena nastavitev za konfiguracijo TranslatePress v trenutku!','It takes less than a minute.'=>'Traja manj kot minuto.','Scanning item %1$d of %2$d...'=>'Skeniranje elementa %1$d od %2$d...','Manually translated'=>'Ročno prevedeno','Automatically translated'=>'Samodejno prevedeno','Not translated'=>'Neprevedeno','Bulk Actions'=>'Skupna dejanja','Delete entries'=>'Izbriši vnose','Edit'=>'Uredi','Delete'=>'Izbriši','Filter'=>'Filtriraj','Clear filters'=>'Počisti filtre','Add New'=>'Dodaj novo','Rescan plugins and theme for strings'=>'Ponovno preišči vtičnike in temo za nize','Scanning plugins and theme for strings...'=>'Preiskovanje vtičnikov in teme za nize...','Plugins and theme scan is complete'=>'Preiskovanje vtičnikov in teme je zaključeno','Plugins and theme scan did not finish due to an error'=>'Preiskovanje vtičnikov in teme se zaradi napake ni zaključilo','Import / Export'=>'Uvoz / Izvoz','items'=>'elementi','See More'=>'Prikaži več','See Less'=>'Prikaži manj','Apply'=>'Uporabi','No strings match your query.'=>'Noben niz ne ustreza vaši poizvedbi.','Try to rescan plugins and theme for strings.'=>'Poskusite ponovno preiskati vtičnike in temo za nize.','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'Med nalaganjem rezultatov je prišlo do napake. Najverjetneje ste bili odjavljeni. Želite ponovno naložiti stran?','found in translation'=>'najdeno v prevodu','Select All'=>'Izberi vse','Select Visible'=>'Izberi vidne','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'Dejanje boste izvedli na vseh nizih, ki ustrezajo vašemu filtru, ne le na vidno označenih. Če želite izvesti dejanje samo na vidnih nizih, kliknite »Izberi vidne« v spustnem meniju glave tabele.','You are about to perform this action only on the visible strings. To perform the action on all the strings matching the filter click "Select All" from the table header dropdown.'=>'Dejanje boste izvedli samo na vidnih nizih. Če želite izvesti dejanje na vseh nizih, ki ustrezajo filtru, kliknite »Izberi vse« v spustnem meniju glave tabele.','To continue please type the word:'=>'Če želite nadaljevati, vnesite besedo:','The word typed was incorrect. Action was cancelled.'=>'Vnesena beseda je bila napačna. Dejanje je bilo preklicano.','Warning: This action cannot be undone. Deleting a string will remove its current translation. The original string will appear again in this interface after TranslatePress detects it. This action is NOT equivalent to excluding the string from being translated again.'=>'Opozorilo: Tega dejanja ni mogoče razveljaviti. Brisanje niza bo odstranilo njegov trenutni prevod. Izvirni niz se bo v tem vmesniku znova prikazal, ko ga bo TranslatePress zaznal. To dejanje NI enakovredno izključitvi niza iz ponovnega prevajanja.','%d original entries and their translations were deleted.'=>'%d izvirnih vnosov in njihovi prevodi so bili izbrisani.','Navigate to next page'=>'Pojdi na naslednjo stran','Navigate to previous page'=>'Pojdi na prejšnjo stran','Navigate to first page'=>'Pojdi na prvo stran','Navigate to last page'=>'Pojdi na zadnjo stran','Type a page number to navigate to'=>'Vnesite številko strani, na katero se želite pomakniti','Incorrect page number. Type a page number between 1 and total number of pages'=>'Nepravilna številka strani. Vnesite številko med 1 in skupnim številom strani.','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'Išči izvirne in prevedene nize, ki vsebujejo vnesene ključne besede, ter hkrati ustrezajo izbranim filtrom. Za natančno ujemanje postavite niz v narekovaje: "niz"','Filter strings according to selected translation status, filters and keywords and selected filters'=>'Filtriraj nize glede na izbrani status prevoda, filtre in ključne besede ter izbrane filtre','Removes selected filters'=>'Odstrani izbrane filtre','See options for selecting all strings'=>'Oglejte si možnosti za izbiro vseh nizov','Click to sort strings by this column'=>'Kliknite za razvrščanje nizov po tem stolpcu','Language in which the translation status filter applies. Leave unselected for the translation status to apply to ANY language'=>'Jezik, na katerega se nanaša filter statusa prevoda. Pustite neizbrano, če naj se status prevoda nanaša na KATERIKOLI jezik.','Search'=>'Išči','Slugs that are not found in either one of the other categories.'=>'Slugi, ki jih ni v nobeni od drugih kategorij.','Plugins and Theme String Translation'=>'Prevajanje nizov vtičnikov in teme','Gettext'=>'Gettext','Search Gettext Strings'=>'Iskanje Gettext nizov','ID'=>'ID','Original String'=>'Izvirni niz','Translation'=>'Prevod','Filter by domain'=>'Filtriraj po domeni','Filter by type'=>'Filtriraj po vrsti','Email text'=>'Besedilo e-pošte','Emails String Translation'=>'Prevajanje e-poštnih nizov','Emails'=>'E-pošta','Search Email Strings'=>'Išči e-poštne nize','User Inputted String Translation'=>'Prevajanje nizov uporabniškega vnosa','Regular'=>'Navadni','Search Regular Strings'=>'Išči navadne nize','Filter by Translation Block'=>'Filtriraj po bloku prevajanja','URL Slugs Translation'=>'Prevajanje URL slugov','String Translation Editor'=>'Urejevalnik prevajanja nizov','TranslatePress has detected and cleaned up some failed translation entries in your database following %1$san isolated incident%2$s. No further action is required.'=>'TranslatePress je v vaši bazi podatkov po %1$sposameznem incidentu%2$s zaznal in počistil nekatere neuspele prevajalske vnose. Nadaljnje dejanje ni potrebno.','Post Slug'=>'Slug objave','Invalid language code'=>'Neveljavna koda jezika','First by browser language, then IP address (recommended)'=>'Najprej po jeziku brskalnika, nato po IP naslovu (priporočeno)','First by IP address, then by browser language'=>'Najprej po IP naslovu, nato po jeziku brskalnika','Only by browser language'=>'Samo po jeziku brskalnika','Only by IP address'=>'Samo po naslovu IP','A popup appears asking the user if they want to be redirected'=>'Pojavi se pojavno okno, ki uporabnika vpraša, ali želi biti preusmerjen','Redirect directly (*not recommended)'=>'Neposredna preusmeritev (*ni priporočljivo)','Pop-up window over the content'=>'Pojavno okno nad vsebino','Hello bar before the content'=>'Obvestilna vrstica pred vsebino','WARNING. Cannot determine your language preference based on your current IP.<br>This is most likely because the website is on a local environment.'=>'OPOZORILO. Na podlagi vašega trenutnega naslova IP ni mogoče določiti vaše jezikovne preference.<br>To je najverjetneje zato, ker je spletišče v lokalnem okolju.','Go to <a href="%s" target="_self">Advanced</a> tab to change this feature\'s settings'=>'Pojdite na zavihek <a href="%s" target="_self">Napredno</a>, da spremenite nastavitve te funkcije','User Language Detection Method'=>'Način zaznavanja jezika uporabnika','Select how the language should be detected for first time visitors.<br>The visitor\'s last displayed language will be remembered through cookies.'=>'Izberite, kako naj se zaznava jezik za obiskovalce, ki so tu prvič.<br>Zadnji prikazani jezik obiskovalca bo zapomnjen s pomočjo piškotov.','User Notification Popup'=>'Pojavno okno z obvestilom uporabniku','A popup appears asking the user if they want to be redirected.'=>'Pojavi se pojavno okno, ki uporabnika vpraša, ali želi biti preusmerjen.','Popup Type'=>'Vrsta pojavnega okna','Popup Text'=>'Besedilo pojavnega okna','The same text is displayed in all languages. <br>A selecting language switcher will be appended to the pop-up. The detected language is pre-selected.'=>'Enako besedilo je prikazano v vseh jezikih.<br>K pojavnemu oknu bo dodan izbirnik jezikov. Zaznani jezik je vnaprej izbran.','Button Text'=>'Besedilo gumba','Write the text you wish to appear on the button..'=>'Zapišite besedilo, ki naj se prikaže na gumbu.','Close Button Text'=>'Besedilo gumba za zapiranje','Write the text you wish to appear on the close button. Leave empty for just the close button.'=>'Zapišite besedilo, ki naj se prikaže na gumbu za zapiranje. Pustite prazno, če želite samo gumb za zapiranje.','Bad request. There was an error accessing the DeepL API.'=>'Napačna zahteva. Pri dostopu do DeepL API je prišlo do napake.','The API key entered is invalid.'=>'Vneseni API ključ je neveljaven.','The API resource could not be found.'=>'Vira API ni bilo mogoče najti.','The request size is too large.'=>'Velikost zahteve je prevelika.','The request is too long.'=>'Zahteva je predolga.','Too many requests. Please try again later.'=>'Preveč zahtev. Poskusite znova pozneje.','Your translation quota has been reached.'=>'Vaša kvota za prevode je bila dosežena.','We could not process your request. Please try again later.'=>'Vaše zahteve nismo mogli obdelati. Poskusite znova pozneje.','There is an error on the DeepL service and your request could not be processed.'=>'V storitvi DeepL je prišlo do napake in vaše zahteve ni bilo mogoče obdelati.','DeepL API Type'=>'Vrsta DeepL API','Pro'=>'Pro','Free'=>'Brezplačno','Select the type of DeepL API you want to use.'=>'Izberite vrsto DeepL API, ki jo želite uporabljati.','DeepL API Key'=>'Ključ DeepL API','Visit <a href="%s" target="_blank">this link</a> to see how you can set up an API key and control API costs.'=>'Obiščite <a href="%s" target="_blank">to povezavo</a>, da vidite, kako lahko nastavite API ključ in nadzorujete stroške API.','Translator'=>'Prevajalec',' TranslatePress Settings'=>' Nastavitve TranslatePress','Allow this user to translate the website.'=>'Dovoli temu uporabniku prevajanje spletnega 